const input = $input.first().json;
const command = (input.command || '').toLowerCase().trim();

// Determine sub-action
let action = input.action || 'unknown';
if (action === 'unknown') {
  if (command.includes('draft')) action = 'draft';
  else if (command.includes('send')) action = 'send';
  else if (command.includes('summarize') || command.includes('summary')) action = 'summarize';
}

// Validate required fields
if (!command) {
  throw new Error('No command text provided to email agent');
}

return [{
  json: {
    command: input.command,
    action: action,
    parameters: input.parameters || {},
    execution_id: input.execution_id || $execution.id,
    timestamp: new Date().toISOString()
  }
}];

// Human approval gate for send operations
// In production, replace with n8n Form/Wait node or external approval webhook
const input = $input.first().json;

return [{
  json: {
    ...input,
    approval_status: 'pending',
    approval_required: true,
    approval_reason: 'write_operation_send_email',
    approval_message: `Approval required to send email. Command: "${input.command}"`,
    queued_at: new Date().toISOString()
  }
}];

const input = $input.first().json;
return [{
  json: {
    agent: '1000-agent-email',
    action: input.action,
    confidence: 0.2,
    result: {
      error: `Unsupported email action: ${input.action}`,
      supported_actions: ['draft', 'send', 'summarize']
    },
    requires_approval: false,
    execution_time_ms: 0
  }
}];

const startTime = new Date($('Parse Email Command').first().json.timestamp).getTime();
const input = $input.first().json;
const parsed = $('Parse Email Command').first().json;

// Parse AI response if present
let result = {};
let confidence = 0.5;

try {
  if (input.choices) {
    // OpenAI response
    const content = JSON.parse(input.choices[0].message.content);
    result = content;
    confidence = 0.9;
  } else if (input.approval_required) {
    // Approval gate response
    result = { message: input.approval_message, status: 'pending_approval' };
    confidence = 0.85;
  } else {
    result = input.result || input;
    confidence = input.confidence || 0.5;
  }
} catch (e) {
  result = { raw: input, parse_error: e.message };
  confidence = 0.4;
}

const executionTime = Date.now() - startTime;

return [{
  json: {
    agent: '1000-agent-email',
    action: parsed.action,
    confidence: confidence,
    result: result,
    requires_approval: parsed.action === 'send',
    approval_reason: parsed.action === 'send' ? 'write_operation' : null,
    execution_time_ms: executionTime,
    execution_id: parsed.execution_id
  }
}];
